from flask import Flask, request, session, redirect, url_for
import requests

app = Flask(__name__)

# Configure your client ID and secret
CLIENT_ID = "your-client-id"
CLIENT_SECRET = "your-client-secret"

@app.route("/")
def index():
    # Initiate authorization flow
    redirect_uri = request.args.get("redirect_uri")
    if not redirect_uri:
        return "Missing redirect URI"
    
    domain = urlparse(redirect_uri).netloc.split(".").pop()
    if domain not in ["example1.com", "example2.com"]:
        return "Invalid redirect URI"
    
    # Redirect to the authorization URL
    return redirect(url_for(".authorize"), code=302)

@app.route("/authorize")
def authorize():
    # Exchange the authorization code for an access token
    code = request.args.get("code")
    if not code:
        return "Missing authorization code"
    
    response = requests.post(
        "https://example.com/oauth/token",
        data={
            "grant_type": "authorization_code",
            "code": code,
            "redirect_uri": redirect_uri,
            "client_id": CLIENT_ID,
            "client_secret": CLIENT_SECRET
        }
    )
    
    if response.status_code != 200:
        return "Failed to exchange code for token"
    
    # Extract the access token from the response
    access_token = response.json()["access_token"]
    
    # Use the access token to make an API call
    response = requests.get(
        "https://example.com/api/data",
        headers={"Authorization": f"Bearer {access_token}"}
    )
    
    if response.status_code != 200:
        return "Failed to retrieve data"
    
    # Return the API response
    return response.json()